import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Sidebar: React.FC = () => {
  const location = useLocation();
  const { user } = useAuth();

  const menuItems = [
    { path: '/', icon: '🏠', label: 'Dashboard' },
    { path: '/animals', icon: '🐷', label: 'Animales' },
    { path: '/reproduction', icon: '❤️', label: 'Reproducción' },
    { path: '/weights', icon: '⚖️', label: 'Pesajes' },
    { path: '/health', icon: '🏥', label: 'Sanidad' },
    { path: '/locations', icon: '📍', label: 'Ubicaciones' },
    { path: '/finance', icon: '💰', label: 'Finanzas' },
    { path: '/genealogy', icon: '🧬', label: 'Genealogía' },
    { path: '/nutrition', icon: '🌾', label: 'Nutrición' },
    { path: '/reports', icon: '📊', label: 'Reportes' },
    { path: '/users', icon: '👥', label: 'Usuarios' },
    { path: '/analytics', icon: '🤖', label: 'Analytics' }
  ];

  return (
    <div className="sidebar">
      <div style={{ padding: '20px', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>
        <div style={{ 
          display: 'flex', 
          alignItems: 'center', 
          gap: '10px',
          color: '#ffffff',
          fontSize: '20px',
          fontWeight: '700'
        }}>
          <span style={{ fontSize: '28px' }}>🚀</span>
          <span>SGP</span>
        </div>
        <div style={{ 
          color: 'rgba(255,255,255,0.7)', 
          fontSize: '12px',
          marginTop: '5px'
        }}>
          Sistema de Gestión Porcina
        </div>
      </div>

      <div style={{ padding: '20px 0' }}>
        {menuItems.map((item) => (
          <Link
            key={item.path}
            to={item.path}
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: '12px',
              padding: '12px 25px',
              color: location.pathname === item.path ? '#ffffff' : 'rgba(255,255,255,0.7)',
              textDecoration: 'none',
              background: location.pathname === item.path ? 'rgba(21, 114, 232, 0.2)' : 'transparent',
              borderRight: location.pathname === item.path ? '3px solid #1572e8' : '3px solid transparent',
              transition: 'all 0.3s ease',
              fontSize: '14px',
              fontWeight: location.pathname === item.path ? '600' : '500'
            }}
          >
            <span style={{ fontSize: '18px' }}>{item.icon}</span>
            <span>{item.label}</span>
          </Link>
        ))}
      </div>

      <div style={{ 
        position: 'absolute', 
        bottom: '20px', 
        left: '20px', 
        right: '20px',
        padding: '15px',
        background: 'rgba(255,255,255,0.1)',
        borderRadius: '8px'
      }}>
        <div style={{ color: '#ffffff', fontSize: '14px', fontWeight: '600' }}>
          {user?.nombre}
        </div>
        <div style={{ color: 'rgba(255,255,255,0.7)', fontSize: '12px', textTransform: 'capitalize' }}>
          {user?.rol}
        </div>
      </div>
    </div>
  );
};

export default Sidebar;
